using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch in root component
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint0 = Point3D::create(0, 0, 0);
    if (!centerPoint0)
        return false;
    Ptr circle0 = sketchCircles->addByCenterRadius(centerPoint0, 5.0);
    if (!circle0)
        return false;
    Ptr centerPoint1 = Point3D::create(10, 10, 0);
    if (!centerPoint1)
        return false;
    Ptr circle1 = sketchCircles->addByCenterRadius(centerPoint1, 5.0);
    if (!circle1)
        return false;

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof0 = profs->item(0);
    if (!prof0)
        return false;
    Ptr prof1 = profs->item(1);
    if (!prof1)
        return false;

    // Create an extrusion input and make sure it's in a new component
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof0, FeatureOperations::NewComponentFeatureOperation);
    if (!extInput)
        return false;

    // Set the extrusion input
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(true, distance);
    extInput->isSolid(true);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the side face of the created extrusion body
    Ptr sideFaces = ext->sideFaces();
    if (!sideFaces)
        return false;
    Ptr sideFace = sideFaces->item(0);
    if (!sideFace)
        return false;

    // Create the first joint geometry with the side face
    Ptr geo0 = JointGeometry::createByNonPlanarFace(sideFace, JointKeyPointTypes::StartKeyPoint);
    if (!geo0)
        return false;

    // Create the second joint geometry with prof1
    Ptr geo1 = JointGeometry::createByProfile(prof1, circle1, JointKeyPointTypes::CenterKeyPoint);
    if (!geo1)
        return false;

    // Create joint input
    Ptr joints = rootComp->joints();
    if (!joints)
        return false;
    Ptr jointInput = joints->createInput(geo0, geo1);
    if (!jointInput)
        return false;

    // Set the joint input
    Ptr angle = ValueInput::createByString("90 deg");
    if (!angle)
        return false;
    jointInput->angle(angle);
    Ptr offset = ValueInput::createByString("1 cm");
    if (!offset)
        return false;
    jointInput->offset(offset);
    jointInput->isFlipped(true);
    jointInput->setAsRevoluteJointMotion(JointDirections::YAxisJointDirection);

    // Create the joint
    Ptr joint = joints->add(jointInput);
    if (!joint)
        return false;

    Ptr revoluteMotion = joint->jointMotion();
    if (!revoluteMotion)
        return false;
    Ptr limits = revoluteMotion->rotationLimits();
    if (!limits)
        return false;
    limits->isMinimumValueEnabled(true);
    limits->minimumValue(3.14 / 3);
    limits->isMaximumValueEnabled(true);
    limits->maximumValue(3.14 / 3 * 2);

    return true;
}
